import { useNavigate } from "react-router-dom";

function Navbar(){

const navigate = useNavigate();

return(

<div style={{
height:"60px",
background:"#f1f5f9",
display:"flex",
alignItems:"center",
justifyContent:"space-between",
padding:"0 20px"
}}>

<h3>Unified Resource Management System</h3>

<button onClick={()=>navigate("/")}>
Logout
</button>

</div>

)

}

export default Navbar;
